<div class="page-title"><h2>Almacenes y transferencias</h2></div><div class="grid two"><div class="card"><h3>Crear almacén</h3><form method="post" action="/warehouses" class="form"><?= csrf_field() ?><label>Nombre<input name="name" required></label><label>Ubicación<input name="location"></label><button class="btn">Guardar</button></form></div><div class="card"><h3>Transferencia entre almacenes</h3><form method="post" action="/warehouses/transfer" class="form two-cols"><?= csrf_field() ?><label>Producto<select name="product_id"><?php foreach($products as $p): ?><option value="<?= $p['id'] ?>"><?= e($p['name']) ?></option><?php endforeach; ?></select></label><label>Cantidad<input type="number" step="0.01" name="quantity" required></label><label>Desde<select name="from_warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?= $w['id'] ?>"><?= e($w['name']) ?></option><?php endforeach; ?></select></label><label>Hacia<select name="to_warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?= $w['id'] ?>"><?= e($w['name']) ?></option><?php endforeach; ?></select></label><button class="btn col-span-2">Transferir</button></form></div></div><div class="grid two"><div class="card"><h3>Listado de almacenes</h3><table class="table"><thead><tr><th>ID</th><th>Nombre</th><th>Ubicación</th></tr></thead><tbody><?php foreach($warehouses as $w): ?><tr><td><?= $w['id'] ?></td><td><?= e($w['name']) ?></td><td><?= e($w['location']) ?></td></tr><?php endforeach; ?></tbody></table></div><div class="card"><h3>Historial de transferencias</h3><table class="table"><thead><tr><th>Fecha</th><th>Producto</th><th>Desde</th><th>Hacia</th><th>Cantidad</th></tr></thead><tbody><?php foreach($transfers as $t): ?><tr><td><?= e($t['created_at']) ?></td><td><?= e($t['product_name']) ?></td><td><?= e($t['from_name']) ?></td><td><?= e($t['to_name']) ?></td><td><?= money($t['quantity']) ?></td></tr><?php endforeach; ?></tbody></table></div></div>
